import React, { useState, useEffect, useRef } from 'react';
import { useAuth } from '../context/AuthContext';
import API from '../services/api';
import io from 'socket.io-client';
import './ChatBot.css';

const ChatBot = () => {
  const { user, isAuthenticated } = useAuth();
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState([]);
  const [inputMessage, setInputMessage] = useState('');
  const [agents, setAgents] = useState([]);
  const [selectedAgent, setSelectedAgent] = useState(null);
  const [socket, setSocket] = useState(null);
  const [isConnected, setIsConnected] = useState(false);
  const messagesEndRef = useRef(null);

  useEffect(() => {
    if (isAuthenticated) {
      fetchAgents();
      initializeSocket();
    }

    return () => {
      if (socket) {
        socket.disconnect();
      }
    };
  }, [isAuthenticated]);

  useEffect(() => {
    if (selectedAgent && user) {
      loadChatHistory();
    }
  }, [selectedAgent, user]);

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const initializeSocket = () => {
    const newSocket = io('http://localhost:5000');
    setSocket(newSocket);

    newSocket.on('connect', () => {
      setIsConnected(true);
      if (user) {
        newSocket.emit('join-room', `user-${user._id}`);
      }
    });

    newSocket.on('disconnect', () => {
      setIsConnected(false);
    });

    newSocket.on('receive-message', (data) => {
      setMessages(prev => [...prev, {
        _id: Date.now(),
        message: data.message,
        sender: data.sender,
        createdAt: new Date(data.timestamp)
      }]);
    });

    return () => newSocket.close();
  };

  const fetchAgents = async () => {
    try {
      const response = await API.get('/users?role=agent');
      setAgents(response.data.data);
      if (response.data.data.length > 0 && !selectedAgent) {
        setSelectedAgent(response.data.data[0]);
      }
    } catch (error) {
      console.error('Error fetching agents:', error);
    }
  };

  const loadChatHistory = async () => {
    try {
      const response = await API.get(`/chat/${selectedAgent._id}`);
      setMessages(response.data.data);
    } catch (error) {
      console.error('Error loading chat history:', error);
      setMessages([]);
    }
  };

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  const handleSendMessage = async (e) => {
    e.preventDefault();
    
    if (!inputMessage.trim() || !selectedAgent) return;

    try {
      // Save to database
      const response = await API.post('/chat/send', {
        receiver: selectedAgent._id,
        message: inputMessage
      });

      // Send via Socket.io
      if (socket && isConnected) {
        socket.emit('send-message', {
          roomId: `user-${selectedAgent._id}`,
          message: inputMessage,
          sender: user,
          timestamp: new Date()
        });
      }

      // Add to local messages
      setMessages(prev => [...prev, response.data.data]);
      setInputMessage('');
    } catch (error) {
      console.error('Error sending message:', error);
      alert('Failed to send message');
    }
  };

  if (!isAuthenticated) {
    return (
      <>
        <div className="chat-toggle" onClick={() => alert('Please login to chat with agents!')}>
          <div className="toggle-icon">💬</div>
        </div>
      </>
    );
  }

  return (
    <>
      {/* Chat Toggle Button */}
      <div className={`chat-toggle ${isOpen ? 'active' : ''}`} onClick={() => setIsOpen(!isOpen)}>
        <div className="toggle-icon">
          {isOpen ? '✕' : '💬'}
        </div>
        {!isOpen && messages.length > 0 && (
          <div className="notification-badge">
            <span className="pulse-dot"></span>
          </div>
        )}
      </div>

      {/* Chat Window */}
      <div className={`chat-window ${isOpen ? 'open' : ''}`}>
        {/* Chat Header */}
        <div className="chat-header">
          <div className="chat-header-content">
            <div className="agent-avatar-chat">
              <span>👨‍💼</span>
              <div className={`status-dot ${isConnected ? 'online' : 'offline'}`}></div>
            </div>
            <div className="agent-info-chat">
              <h4>{selectedAgent?.name || 'Select Agent'}</h4>
              <p className="status-text">{isConnected ? '🟢 Online' : '🔴 Offline'}</p>
            </div>
          </div>
          <button className="chat-close" onClick={() => setIsOpen(false)}>
            ✕
          </button>
        </div>

        {/* Agent Selection */}
        {agents.length > 1 && (
          <div className="agent-selector">
            <label>Chat with:</label>
            <select 
              value={selectedAgent?._id || ''} 
              onChange={(e) => {
                const agent = agents.find(a => a._id === e.target.value);
                setSelectedAgent(agent);
              }}
              className="agent-select"
            >
              {agents.map(agent => (
                <option key={agent._id} value={agent._id}>
                  {agent.name} - {agent.email}
                </option>
              ))}
            </select>
          </div>
        )}

        {/* Messages Area */}
        <div className="chat-messages">
          {messages.length === 0 ? (
            <div className="no-messages">
              <div className="no-msg-icon">💬</div>
              <p>Start a conversation with {selectedAgent?.name}</p>
            </div>
          ) : (
            messages.map((msg, index) => (
              <div 
                key={msg._id || index} 
                className={`message ${msg.sender._id === user._id ? 'own' : 'other'}`}
              >
                {msg.sender._id !== user._id && (
                  <div className="message-avatar">
                    👨‍💼
                  </div>
                )}
                <div className="message-content">
                  {msg.sender._id !== user._id && (
                    <div className="message-sender">{msg.sender.name}</div>
                  )}
                  <div className="message-bubble">
                    {msg.message}
                  </div>
                  <div className="message-time">
                    {new Date(msg.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </div>
                </div>
              </div>
            ))
          )}
          <div ref={messagesEndRef} />
        </div>

        {/* Input Area */}
        <form className="chat-input-area" onSubmit={handleSendMessage}>
          <input
            type="text"
            value={inputMessage}
            onChange={(e) => setInputMessage(e.target.value)}
            placeholder="Type your message..."
            className="chat-input"
          />
          <button 
            type="submit" 
            className="chat-send-btn"
            disabled={!inputMessage.trim()}
          >
            <span className="send-icon">📤</span>
          </button>
        </form>
      </div>
    </>
  );
};

export default ChatBot;
